import{_ as i,o as t,c as l,ag as a}from"./chunks/framework.CMYkYJvz.js";const f=JSON.parse('{"title":"项目概览","description":"用几分钟理解 Bifrost 的定位、能力边界和适合的使用场景。","frontmatter":{"title":"项目概览","description":"用几分钟理解 Bifrost 的定位、能力边界和适合的使用场景。","editLink":false},"headers":[],"relativePath":"getting-started/overview.md","filePath":"getting-started/overview.md"}'),o={name:"getting-started/overview.md"};function r(s,e,d,c,n,u){return t(),l("div",null,[...e[0]||(e[0]=[a('<blockquote><p>此页面由 <code>docs/overview.md</code> 自动同步生成。</p></blockquote><h1 id="bifrost-是什么" tabindex="-1">Bifrost 是什么 <a class="header-anchor" href="#bifrost-是什么" aria-label="Permalink to &quot;Bifrost 是什么&quot;">​</a></h1><p>Bifrost 是一个由 Rust 编写的高性能代理服务器，灵感来源于 Whistle，但目标不只是“转发请求”，而是把规则、脚本、流量观测、TLS MITM 与回放工作流整合进同一套体验里。</p><h2 id="适合谁" tabindex="-1">适合谁 <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁&quot;">​</a></h2><ul><li>需要本地代理做接口调试的后端与前端开发者</li><li>需要抓包、改写请求或验证边界场景的测试工程师</li><li>需要自定义脚本逻辑和复杂规则编排的高级用户</li><li>需要桌面端工作流的网络调试与协议排查场景</li></ul><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li>支持 HTTP/1.1、HTTP/2、HTTP/3、HTTPS、SOCKS5、WebSocket 与 SSE</li><li>支持 TLS MITM、证书管理与按域名透传/拦截</li><li>提供丰富的 Rules 语法，用于改写、路由、Mock、注入与限流</li><li>内置 QuickJS 沙箱脚本能力，适合处理动态逻辑</li><li>内置 Web UI，可查看流量、编辑规则、回放请求与追踪脚本日志</li><li>支持临时端口绑定，让一个常驻代理服务按入口端口隔离不同任务的规则和流量</li><li>支持 remote-invoke，用于在授权后查询远端流量、读取/修改远端文件、执行受策略约束的远端命令</li><li>支持 Agent Skill 安装，把真实 traffic 证据交给 Agent 做协议理解与业务自动化沉淀</li></ul><h2 id="产品形态" tabindex="-1">产品形态 <a class="header-anchor" href="#产品形态" aria-label="Permalink to &quot;产品形态&quot;">​</a></h2><ul><li><code>CLI</code>：适合脚本化、集成和服务化部署</li><li><code>Desktop</code>：适合日常代理调试和本地使用</li><li><code>Web UI</code>：适合流量检视、规则管理和可视化操作</li></ul>',9)])])}const _=i(o,[["render",r]]);export{f as __pageData,_ as default};
